import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import { LineChart } from '@mui/x-charts';
import response from './response.json';

interface CurrentGeneration {
  power: number;
  unit: string;
  condition: string;
}

interface DailyYield {
  hour: string;
  energy: number;
}

interface MonthlySavings {
  amount: number;
  currency: string;
}

interface SolarData {
  currentGeneration: CurrentGeneration;
  dailyYield: DailyYield[];
  monthlySavings: MonthlySavings;
}

export default function Widget() {
  const solarData = response.data as SolarData;
  const { currentGeneration, dailyYield, monthlySavings } = solarData;
  const clipPathId = useId();

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 500, bgcolor: '#FFF8E1' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" color="text.primary" sx={{ mb: 0.5 }}>
              Solar Power Generation
            </Typography>
            <Typography variant="h4" fontWeight={700} color="text.secondary">
              {currentGeneration.power} {currentGeneration.unit}
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Condition: {currentGeneration.condition}
            </Typography>
          </Box>

          <Box sx={{ width: '100%', height: 120 }}>
            <LineChart
              height={120}
              series={[
                {
                  data: dailyYield.map(d => d.energy),
                  color: '#FFC107',
                  curve: 'natural',
                  showMark: false,
                },
              ]}
              xAxis={[
                {
                  data: dailyYield.map(d => d.hour),
                  scaleType: 'band',
                  tickLabelStyle: {
                    fontSize: 10,
                    fill: '#6B7280',
                  },
                },
              ]}
              margin={{
                top: 10,
                bottom: 30,
                left: 40,
                right: 10,
              }}
              sx={{
                '& .MuiLineElement-root': {
                  strokeWidth: 2,
                },
              }}
            />
          </Box>

          <Box>
            <Typography variant="body2" color="text.secondary">
              Monthly Savings
            </Typography>
            <Typography variant="h5" fontWeight={600} color="primary">
              {monthlySavings.currency} {monthlySavings.amount.toFixed(2)}
            </Typography>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
